    public final DisplayModel model;

    SpiderTorsoModels(DisplayModel model) {
        this.model = model;
        // Flag quartz block tags for active cloaking
        for (BlockDisplayModelPiece p : this.model.pieces) {
            p.tags.add("torso");
            if (p.blockName.equals("smooth_quartz")) {
                p.tags.add("cloak");
            }
        }
    }
